class Solution:
    def countSubarrays(self, nums: List[int], k: int) -> int:
        count = 0
        prev = []
        for num in nums:
            current = []
            if prev:
                for val in prev:
                    current.append(val & num)
                current.append(num)
            else:
                current = [num]
            count += current.count(k)
