class Solution:
    def minimumLength(self, s: str) -> int:
        left = 0
        right = len(s) - 1
        while left < right:
            if s[left] == s[right]:
                left += 1
                right -= 1
            else:
                if s[left] < s[right]:
                    left += 1
                else:
                    right -= 1
        return right - left + 1

