class Solution:
    def timeTaken(self, edges: List[List[int]]) -> List[int]:
        n = len(edges) + 1
        adj = [[] for _ in range(n)]
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)

        result = []

        for s in range(n):
            time = [-1] * n
            time[s] = 0
            q = deque([s])
            max_time = 0
            while q:
                u = q.popleft()
                for v in adj[u]:
                    if time[v] == -1:
                        if v % 2 == 1:
                            time[v] = time[u] + 1
                        else:
                            time[v] = time[u] + 2
                        q.append(v)
                        if time[v] > max_time:
                            max_time = time[v]
            result.append(max_time)

        return result

