def decompose_cycles(P, N):
    visited = [False] * (N + 1)  # 1-based indexing
    cycles = []
    for i in range(1, N + 1):
        if not visited[i]:
            current = i
            cycle = []
            while not visited[current]:
                visited[current] = True
                cycle.append(current)
                current = P[current - 1]  # P is 0-based in the list
            cycles.append(cycle)
    return cycles

def extended_gcd(a, b):
    if b == 0:
        return (a, 1, 0)
    else:
        g, x, y = extended_gcd(b, a % b)
        return (g, y, x - (a // b) * y)

def crt(a1, m1, a2, m2):
    # Solve x ≡ a1 mod m1
    # x ≡ a2 mod m2
    # returns (x, m) or None if no solution
    g, x, y = extended_gcd(m1, m2)
    if (a2 - a1) % g != 0:
        return None
    lcm = m1 // g * m2
    x0 = (a1 + (a2 - a1) // g * x * m1) % lcm
    return (x0, lcm)

