MOD = 998244353

def main():
    N, M = map(int, sys.stdin.readline().split())

    primes = [2, 3, 5, 7, 11, 13]
    max_exponents = [4, 2, 1, 1, 0, 0]

    # Generate all possible exponents vectors
    states = []
    for e2 in range(0, max_exponents[0]+1):
        for e3 in range(0, max_exponents[1]+1):
            for e5 in range(0, max_exponents[2]+1):
                for e7 in range(0, max_exponents[3]+1):
                    states.append( (e2, e3, e5, e7, 0, 0) )

    state_to_index = {state: i for i, state in enumerate(states)}
    S = len(states)

    # Function to get exponents of x
    def get_exponents(x):
        ex = [0] * len(primes)
        for i, p in enumerate(primes):
            count = 0
            temp = x
            while temp % p == 0:
                count += 1
                temp //= p
            ex[i] = count
        return ex

    # Build transition matrix
    trans = [[0]*S for _ in range(S)]
    for i in range(S):
        current_state = states[i]
        for x in range(1, M+1):
            ex = get_exponents(x)
            new_state = list(current_state)
            for j in range(len(primes)):
                new_state[j] += ex[j]
            new_state_tuple = tuple(new_state)
            if new_state_tuple in state_to_index:
                j = state_to_index[new_state_tuple]
                trans[i][j] += 1

    # Matrix multiplication
    def matrix_mult(a, b):
        n = len(a)
        res = [[0]*n for _ in range(n)]
        for i in range(n):
            for k in range(n):
                if a[i][k]:
                    for j in range(n):
                        res[i][j] = (res[i][j] + a[i][k] * b[k][j]) % MOD
        return res

    # Matrix exponentiation
    def matrix_pow(mat, power):
        n = len(mat)
        res = [[1 if i == j else 0 for j in range(n)] for i in range(n)]
        while power > 0:
            if power % 2 == 1:
                res = matrix_mult(res, mat)
            mat = matrix_mult(mat, mat)
            power //= 2
        return res

    # Matrix addition
    def matrix_add(a, b):
        n = len(a)
        res = [[0]*n for _ in range(n)]
        for i in range(n):
            for j in range(n):
                res[i][j] = (a[i][j] + b[i][j]) % MOD
        return res

    # Compute the sum matrix S = I + A + A^2 + ... + A^N
    A = trans
    if N == 0:
        sum_mat = [[1 if i == j else 0 for j in range(S)] for i in range(S)]
    else:
        def matrix_sum(mat, power):
            n = len(mat)
            res = [[0]*n for _ in range(n)]
            # Initial sum is I
            for i in range(n):
                res[i][i] = 1
            current = mat
            power_remaining = power
            while power_remaining > 0:
                if power_remaining % 2 == 1:
                    res = matrix_add(res, current)
                current = matrix_mult(current, current)
                power_remaining //= 2
            return res

        sum_mat = matrix_sum(A, N)

    # Compute the product terms for each state
    product_terms = [1] * S
    for i in range(S):
        state = states[i]
        prod = 1
        for v in state:
            prod = (prod * (v + 1)) % MOD
        product_terms[i] = prod

    # Compute the result
    result = 0
    for j in range(S):
        if states[j] == (0, 0, 0, 0, 0, 0):
            count = (sum_mat[0][j] - 1) % MOD
        else:
            count = sum_mat[0][j] % MOD
        result = (result + count * product_terms[j]) % MOD

    print(result)

