class Solution:
    def countKConstraintSubstrings(self, s: str, k: int) -> int:
        n = len(s)
        prefix0 = [0] * (n + 1)
        prefix1 = [0] * (n + 1)

        for i in range(n):
            prefix0[i + 1] = prefix0[i] + (s[i] == '0')
            prefix1[i + 1] = prefix1[i] + (s[i] == '1')

        total = 0
        for i in range(n):
            for j in range(i, n):
                count_0 = prefix0[j + 1] - prefix0[i]
                count_1 = (j - i + 1) - count_0
                if count_0 <= k or count_1 <= k:
                    total += 1
        return total

