class Solution:
    def largestPalindrome(self, n: int, k: int) -> str:
        if n == 1:
            return str((9 // k) * k)

        m = (n + 1) // 2
        first_half = '9' * m

        while True:
            # Generate the palindrome
            if n % 2 == 0:
                pal = first_half + first_half[::-1]
            else:
                pal = first_half + first_half[:-1][::-1]

            # Check if the palindrome starts with '0'
            if pal[0] == '0':
                first_half = self.subtract_one(first_half)
                continue

            # Check if divisible by k
            if self.mod(pal, k) == 0:
                return pal

            # Subtract one from the first_half
            first_half = self.subtract_one(first_half)

    def subtract_one(self, s: str) -> str:
        s_list = list(s)
        i = len(s_list) - 1
        while i >= 0 and s_list[i] == '0':
            s_list[i] = '9'
            i -= 1
        if i < 0:
            return '0'
        s_list[i] = str(int(s_list[i]) - 1)
        return ''.join(s_list)

    def mod(self, s: str, k: int) -> int:
        res = 0
        for ch in s:
            res = (res * 10 + int(ch)) % k
        return res

