class Solution:
    def countPairs(self, nums: List[int]) -> int:
        count = 0
        n = len(nums)
        for i in range(n):
            for j in range(i + 1, n):
                if self.is_almost_equal(nums[i], nums[j]):
                    count += 1
        return count

    def is_almost_equal(self, x: int, y: int) -> bool:
        if x == y:
            return True
        s_x = str(x)
        s_y = str(y)

        # Check if swapping two digits in x can make it equal to y
        for i in range(len(s_x)):
            for j in range(i + 1, len(s_x)):
                new_s = list(s_x)
                new_s[i], new_s[j] = new_s[j], new_s[i]
                if int(''.join(new_s)) == y:
                    return True

        # Check if swapping two digits in y can make it equal to x
        for i in range(len(s_y)):
            for j in range(i + 1, len(s_y)):
                new_s = list(s_y)
                new_s[i], new_s[j] = new_s[j], new_s[i]
                if int(''.join(new_s)) == x:
                    return True

        return False

