class Solution:
    def maxScore(self, grid: List[List[int]]) -> int:
        rows = [sorted(row, reverse=True) for row in grid]
        n = len(rows)

        @lru_cache(maxsize=None)
        def backtrack(row_idx, used_set):
            if row_idx == n:
                return 0
            max_sum = 0
            for val in rows[row_idx]:
                if val not in used_set:
                    new_used = used_set.union({val})
                    current_sum = val + backtrack(row_idx + 1, new_used)
                    if current_sum > max_sum:
                        max_sum = current_sum
            return max_sum

        return backtrack(0, frozenset())

