class Solution:
    def maximumSubarrayXor(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        n = len(nums)
        if n == 0:
            return []

        # Precompute max_element[l][r]: maximum element in nums[l..r]
        max_element = [[0] * n for _ in range(n)]
        for l in range(n):
            current_max = nums[l]
            max_element[l][l] = current_max
            for r in range(l + 1, n):
                current_max = max(current_max, nums[r])
                max_element[l][r] = current_max

        # Precompute max_xor[i][j]: maximum XOR of nums[i]^nums[k] for k >= i and <= j
        max_xor = [[0] * n for _ in range(n)]
        for i in range(n):
            current_max = 0
            for j in range(i, n):
                if j == i:
                    current_max = nums[i] ^ nums[j]
                else:
                    current_max = max(current_max, nums[i] ^ nums[j])
                max_xor[i][j] = current_max

        # Precompute max_prefix[r][i]: max of max_xor[i][r] for i from 0 to r
        max_prefix = [[0] * n for _ in range(n)]
        for r in range(n):
            current_max = 0
            for i in range(r, -1, -1):
                if i == r:
                    current_max = max_xor[i][r]
                else:
                    current_max = max(current_max, max_xor[i][r])
                max_prefix[r][i] = current_max

        # Process each query
        res = []
        for l, r in queries:
            max_elem = max_element[l][r]
            # Get the max_xor_val for the range [l, r]
            max_xor_val = max_prefix[r][l]
            res.append(max(max_elem, max_xor_val))

        return res

