            for s in start:
                e = s + d
                current_min = max(prev + k, s)
                if current_min > e:
                    return False
                prev = current_min
            return True

        low = 0
        high = start[-1] + d - start[0]
        answer = 0

        while low <= high:
            mid = (low + high) // 2
            if is_possible(mid):
                answer = mid
                low = mid + 1
            else:
                high = mid - 1

        return answer

