class Line:
    def __init__(self, a, b):
        self.a = a
        self.b = b

    def value(self, x):
        return self.a * x + self.b

class LiChaoNode:
    def __init__(self, l, r):
        self.l = l
        self.r = r
        self.left = None
        self.right = None
        self.line = None

class LiChaoTree:
    def __init__(self, x_min, x_max):
        self.root = LiChaoNode(x_min, x_max)

    def insert(self, node, new_line):
        l = node.l
        r = node.r
        if node.line is None:
            node.line = new_line
            return
        # current line is node.line
        m = (l + r) // 2
        # compare new_line and node.line at m
        curr_val = node.line.value(m)
        new_val = new_line.value(m)
        if new_val > curr_val:
            # swap the lines
            node.line, new_line = new_line, node.line
        # Now check if new_line is better at l or r
        # Check left child
        if l == r:
            return
        if new_line.value(l) > node.line.value(l):
            if node.left is None:
                node.left = LiChaoNode(l, m)
            self.insert(node.left, new_line)
        elif new_line.value(r) > node.line.value(r):
            if node.right is None:
                node.right = LiChaoNode(m+1, r)
            self.insert(node.right, new_line)

    def query(self, node, x):
        if node is None:
            return -float('inf')
        res = node.line.value(x) if node.line else -float('inf')
        m = (node.l + node.r) // 2
        if x <= m:
            left_res = self.query(node.left, x)
            return max(res, left_res)
        else:
            right_res = self.query(node.right, x)
            return max(res, right_res)

class Solution:
    def findMaximumScore(self, nums: List[int]) -> int:
        n = len(nums)
        if n == 0:
            return 0
        max_x = n - 1
        tree = LiChaoTree(0, max_x)
        # For j=0
        dp0 = 0
        line = Line(nums[0], 0)
        tree.insert(tree.root, line)
        # Now process i from 1 to n-1
        for i in range(1, n):
            current_x = i
            max_val = tree.query(tree.root, current_x)
            dp_i = max_val
            a_i = dp_i - i * nums[i]
            line = Line(nums[i], a_i)
            tree.insert(tree.root, line)
        return dp_i

