from collections import deque

class Solution:
    def maxMoves(self, kx: int, ky: int, positions: List[List[int]]) -> int:
        positions_list = [(kx, ky)] + positions
        n = len(positions)

        # Memoization for steps between positions
        memo_steps = {}

        def get_steps(x1: int, y1: int, x2: int, y2: int) -> int:
            if (x1, y1, x2, y2) in memo_steps:
                return memo_steps[(x1, y1, x2, y2)]
            # BFS from (x1, y1) to (x2, y2)
            dist = [[-1 for _ in range(50)] for _ in range(50)]
            q = deque()
            q.append((x1, y1))
            dist[x1][y1] = 0
            while q:
                cx, cy = q.popleft()
                for dx, dy in [(2,1), (1,2), (-1,2), (-2,1), (-2,-1), (-1,-2), (1,-2), (2,-1)]:
                    nx = cx + dx
                    ny = cy + dy
                    if 0 <= nx < 50 and 0 <= ny < 50:
                        if dist[nx][ny] == -1:
                            dist[nx][ny] = dist[cx][cy] + 1
                            q.append((nx, ny))
            result = dist[x2][y2]
            memo_steps[(x1, y1, x2, y2)] = result
            return result

        @lru_cache(maxsize=None)
        def dp(mask: int, current_pos: int, is_alice_turn: bool) -> int:
            if mask == 0:
                return 0
            max_total = -1
            min_total = float('inf')
            for i in range(1, n + 1):
                if (mask & (1 << (i - 1))) != 0:
                    x1, y1 = positions_list[current_pos]
                    x2, y2 = positions_list[i]
                    steps = get_steps(x1, y1, x2, y2)
                    new_mask = mask ^ (1 << (i - 1))
                    new_pos = i
                    if is_alice_turn:
                        total = steps + dp(new_mask, new_pos, False)
                        if total > max_total:
                            max_total = total
                    else:
                        total = steps + dp(new_mask, new_pos, True)
                        if total < min_total:
                            min_total = total
            if is_alice_turn:
                return max_total
            else:
                return min_total

        return dp((1 << n) - 1, 0, True)

class Solution:
    def maxScore(self, a: List[int], b: List[int]) -> int:
        b.sort()
        # Calculate score for taking the last four elements (largest values)
        score1 = a[0] * b[-1] + a[1] * b[-2] + a[2] * b[-3] + a[3] * b[-4]
        # Calculate score for taking the first four elements (smallest values)
        score2 = a[0] * b[0] + a[1] * b[1] + a[2] * b[2] + a[3] * b[3]
        return max(score1, score2)

class Solution:
    def minValidStrings(self, words: List[str], target: str) -> int:
        # Generate all possible prefixes of words
        all_prefixes = set()
        for word in words:
            for l in range(1, len(word) + 1):
                all_prefixes.add(word[:l])

        n = len(target)
        INF = float('inf')
        dp = [INF] * (n + 1)
        dp[0] = 0  # Base case: 0 characters require 0 steps

        for i in range(1, n + 1):
            for l in range(1, i + 1):
                # Check if the substring ending at i with length l is in all_prefixes
                substr = target[i - l:i]
                if substr in all_prefixes:
                    if dp[i - l] + 1 < dp[i]:
                        dp[i] = dp[i - l] + 1

        return dp[n] if dp[n] != INF else -1

