        n = len(nums)
        results = []
        for i in range(n - k + 1):
            is_sorted = True
            # Check if the subarray is sorted in ascending order
            for j in range(i, i + k - 1):
                if nums[j] >= nums[j + 1]:
                    is_sorted = False
                    break
            if not is_sorted:
                results.append(-1)
            else:
                # Check if the elements are consecutive
                if nums[i + k - 1] - nums[i] == k - 1:
                    results.append(nums[i + k - 1])
                else:
                    results.append(-1)
        return results

