class Solution:
    def stringHash(self, s: str, k: int) -> str:
        result = []
        for i in range(0, len(s), k):
            chunk = s[i:i+k]
            total = 0
            for c in chunk:
                total += ord(c) - ord('a')
            hashed = total % 26
            result.append(chr(hashed + ord('a')))
        return ''.join(result)

class Solution:
    def countGoodIntegers(self, n: int, k: int) -> int:
        from math import factorial
        from collections import Counter

        def generate_palindromes(n, k):
            palindromes = set()
            half_length = (n + 1) // 2
            start = 10 ** (half_length - 1)
            end = 10 ** half_length
            for first_half in range(start, end):
                first_str = str(first_half)
                if n % 2 == 0:
                    palindrome_str = first_str + first_str[::-1]
                else:
                    palindrome_str = first_str + first_str[:-1][::-1]
                palindrome = int(palindrome_str)
                if palindrome % k == 0:
                    digits = list(palindrome_str)
                    sorted_digits = tuple(sorted(digits))
                    palindromes.add(sorted_digits)
            return palindromes

        def count_valid_permutations(sorted_digits, n):
            counts = Counter(sorted_digits)
            total = factorial(n)
            for d, cnt in counts.items():
                total //= factorial(cnt)
            has_zero = '0' in counts
            if has_zero:
                new_counts = counts.copy()
                new_counts['0'] -= 1
                if new_counts['0'] < 0:
                    invalid = 0
                else:
                    invalid = factorial(n - 1)
                    for d, cnt in new_counts.items():
                        invalid //= factorial(cnt)
                valid = total - invalid
            else:
                valid = total
            return valid

        unique_multisets = generate_palindromes(n, k)
        total = 0
        for multiset in unique_multisets:
            total += count_valid_permutations(multiset, n)
        return total

