class Solution:
    def maxValue(self, nums: List[int], k: int) -> int:
        n = len(nums)
        # Precompute dp_prefix: dp_prefix[i][m] is the set of OR values for m elements ending at i
        dp_prefix = [[set() for _ in range(k+1)] for _ in range(n)]
        dp_prefix[0][0].add(0)
        if k >= 1:
            dp_prefix[0][1].add(nums[0])
        for i in range(1, n):
            for m in range(0, k+1):
                # Case 1: not taking nums[i]
                dp_prefix[i][m] = set(dp_prefix[i-1][m])
                # Case 2: taking nums[i]
                if m >= 1:
                    prev_set = dp_prefix[i-1][m-1]
                    for x in prev_set:
                        new_or = x | nums[i]
                        dp_prefix[i][m].add(new_or)

        # Precompute dp_suffix: dp_suffix[i][m] is the set of OR values for m elements starting at i
        dp_suffix = [[set() for _ in range(k+1)] for _ in range(n)]
        for i in range(n-1, -1, -1):
            for m in range(0, k+1):
                if m == 0:
                    dp_suffix[i][m].add(0)
                else:
                    if i + m <= n:
                        prev_set = dp_suffix[i+1][m-1]
                        for x in prev_set:
                            new_or = nums[i] | x
                            dp_suffix[i][m].add(new_or)

        max_val = 0
        for i in range(n):
            if len(dp_prefix[i][k]) == 0:
                continue
            if i + 1 < n:
                possible_b_set = dp_suffix[i+1][k]
            else:
                possible_b_set = set()
            for a in dp_prefix[i][k]:
                for b in possible_b_set:
                    current = a ^ b
                    if current > max_val:
                        max_val = current
        return max_val

