class FenwickTree:
    def __init__(self, size):
        self.n = size
        self.tree = [0] * (self.n + 1)  # 1-based indexing

    def update(self, idx, value):
        while idx <= self.n:
            if self.tree[idx] < value:
                self.tree[idx] = value
            else:
                break
            idx += idx & -idx

    def query(self, idx):
        res = 0
        while idx > 0:
            if res < self.tree[idx]:
                res = self.tree[idx]
            idx -= idx & -idx
        return res

class SegmentTree:
    def __init__(self, size):
        self.n = size
        self.size_tree = 1
        while self.size_tree < self.n:
            self.size_tree <<= 1
        self.tree = [0] * (2 * self.size_tree)

    def update(self, pos, value):
        # pos is 1-based
        pos += self.size_tree - 1  # convert to 0-based in the tree
        if self.tree[pos] < value:
            self.tree[pos] = value
            while pos > 1:
                pos >>= 1
                new_val = max(self.tree[2 * pos], self.tree[2 * pos + 1])
                if self.tree[pos] < new_val:
                    self.tree[pos] = new_val
                else:
                    break

    def query_range(self, l, r):
        # l and r are 1-based
        res = 0
        l += self.size_tree - 1
        r += self.size_tree - 1
        while l <= r:
            if l % 2 == 1:
                res = max(res, self.tree[l])
                l += 1
            if r % 2 == 0:
                res = max(res, self.tree[r])
                r -= 1
            l >>= 1
            r >>= 1
        return res

class Solution:
    def maxPathLength(self, coordinates: List[List[int]], k: int) -> int:
        n = len(coordinates)
        # Compress y values
        ys = [y for x, y in coordinates]
        sorted_ys = sorted(ys)
        unique_ys = sorted(list(set(ys)))
        rank = {y: i + 1 for i, y in enumerate(unique_ys)}  # ranks are 1-based
        m = len(unique_ys)

        # Compute ending_length
        # Sort by x increasing, then y increasing
        sorted_ending = sorted([(x, y, i) for i, (x, y) in enumerate(coordinates)], key=lambda t: (t[0], t[1]))
        ending_length = [0] * n
        ft = FenwickTree(m)
        for x, y, idx in sorted_ending:
            r = rank[y]
            max_prev = ft.query(r - 1)
            ending_length[idx] = max_prev + 1
            ft.update(r, ending_length[idx])

        # Compute starting_length
        # Sort by x decreasing, then y decreasing
        sorted_starting = sorted([(x, y, i) for i, (x, y) in enumerate(coordinates)], key=lambda t: (-t[0], -t[1]))
        starting_length = [0] * n
        st = SegmentTree(m)
        # Initialize the segment tree with zeros (no need for explicit updates)
        for x, y, idx in sorted_starting:
            r = rank[y]
            # Query [r+1, m]
            if r + 1 <= m:
                max_prev = st.query_range(r + 1, m)
            else:
                max_prev = 0
            starting_length[idx] = max_prev + 1
            st.update(r, starting_length[idx])

        # The answer is ending_length[k] + starting_length[k] - 1
        return ending_length[k] + starting_length[k] - 1

