class Solution:
    def minNumberOfSeconds(self, mountainHeight: int, workerTimes: List[int]) -> int:
        # Compute the initial high value for binary search
        max_time = 0
        for t in workerTimes:
            time = t * mountainHeight * (mountainHeight + 1) // 2
            if time > max_time:
                max_time = time
        low = 0
        high = max_time

        while low < high:
            mid = (low + high) // 2
            total = 0
            for t in workerTimes:
                if t == 0:
                    x = 0
                else:
                    # Calculate the maximum x for this worker and mid time
                    # Compute upper bound for x
                    high_x = int((2 * mid / t) ** 0.5) + 2
                    low_x = 0
                    # Binary search for x
                    left = 0
                    right = high_x
                    while left <= right:
                        mid_x = (left + right) // 2
                        val = t * mid_x * (mid_x + 1) // 2
                        if val <= mid:
                            left = mid_x + 1
                        else:
                            right = mid_x - 1
                    x = right
                total += x
            if total >= mountainHeight:
                high = mid
            else:
                low = mid + 1
        return low

