    def kthCharacter(self, k: int) -> str:
        def helper(k):
            if k == 1:
                return 'a'
            m = (k - 1).bit_length()
            pos = k - (1 << (m - 1))
            prev_char = helper(pos)
            return chr((ord(prev_char) - ord('a') + 1) % 26 + ord('a'))

        return helper(k)

