class Solution:
    def countOfSubstrings(self, word: str, k: int) -> int:
        vowels = {'a', 'e', 'i', 'o', 'u'}
        n = len(word)
        # Precompute prefix_vowels array
        prefix_vowels = [0] * (n + 1)
        for i in range(n):
            prefix_vowels[i+1] = prefix_vowels[i] + (1 if word[i] in vowels else 0)
        # Precompute positions for each vowel
        positions = {v: [] for v in vowels}
        for i, c in enumerate(word):
            if c in vowels:
                positions[c].append(i)
        count = 0
        # Iterate all possible substrings
        for l in range(n):
            for r in range(l, n):
                length = r - l + 1
                if length < 5 + k:
                    continue
                # Calculate the number of vowels in the substring
                vowel_count = prefix_vowels[r+1] - prefix_vowels[l]
                if vowel_count != length - k:
                    continue
                # Check if all vowels are present in the substring
                valid = True
                for v in vowels:
                    pos_list = positions[v]
                    idx = bisect.bisect_left(pos_list, l)
                    if idx < len(pos_list) and pos_list[idx] <= r:
                        continue
                    else:
                        valid = False
                        break
                if valid:
                    count += 1
        return count

